// kaya runtime for C# guests: loading, the direct-ring occurrence loop,
// and submit. Hand-written; the wire vocabulary next to it
// (KayaWire.cs) is generated by kaya-bindgen.
//
// The direct tier: C# reads the occurrence ring with Volatile loads and
// stores — P/Invoke is crossed only to start the core, to wait on an
// empty ring, and to submit. The consumer contract is the io_uring
// recipe documented in kaya.h.

using System;
using System.Collections.Generic;
using System.Runtime.InteropServices;
using System.Threading;

static class Kaya
{
    [StructLayout(LayoutKind.Sequential)]
    struct RingInfo
    {
        public IntPtr Data;
        public uint Capacity;
        public IntPtr Head;
        public IntPtr Tail;
    }

    [DllImport("kaya")]
    static extern int kaya_run();

    [DllImport("kaya")]
    static extern void kaya_occurrence_ring(out RingInfo info);

    [DllImport("kaya")]
    [return: MarshalAs(UnmanagedType.I1)]
    static extern bool kaya_wait_occurrences();

    [DllImport("kaya")]
    static extern void kaya_submit(byte[] records, nuint len);

    [DllImport("kaya")]
    static extern ulong kaya_blob_register(byte[] bytes, nuint len);

    static RingInfo ring;

    /// On Windows, "kaya" resolves to kaya.dll via PATH. Elsewhere, point
    /// KAYA_LIB at the built library (e.g. target/debug/libkaya.dylib).
    /// Call once, before anything else.
    public static void Init()
    {
        NativeLibrary.SetDllImportResolver(typeof(Kaya).Assembly, (name, _, _) =>
        {
            string env = Environment.GetEnvironmentVariable("KAYA_LIB");
            if (name == "kaya" && env != null && NativeLibrary.TryLoad(env, out IntPtr handle))
                return handle;
            return IntPtr.Zero;
        });
        kaya_occurrence_ring(out ring);
    }

    /// Enter the core on the calling thread (which must be the process
    /// main thread); returns the exit code when the app ends.
    [DllImport("kaya")]
    static extern ulong kaya_spec_hash();

    public static int Run()
    {
        // The stale-artifact guard: this binding was generated from one
        // spec revision; the loaded library must speak the same one.
        if (kaya_spec_hash() != KayaWire.SpecHash)
            throw new InvalidOperationException(
                $"kaya: library speaks spec 0x{kaya_spec_hash():x16}, this binding was " +
                $"generated from 0x{KayaWire.SpecHash:x16} — rebuild the library or " +
                "regenerate bindings");
        return kaya_run();
    }

    /// Submit one transaction: the concatenation of packed records
    /// (KayaWire.Tx* results), applied atomically.
    public static void Submit(params byte[][] records)
    {
        int len = 0;
        foreach (byte[] r in records) len += r.Length;
        byte[] tx = new byte[len];
        int at = 0;
        foreach (byte[] r in records)
        {
            r.CopyTo(tx, at);
            at += r.Length;
        }
        kaya_submit(tx, (nuint)tx.Length);
    }

    /// Register bulk payload bytes (an encoded image) with the core:
    /// one copy into core-owned memory, returning the u64 handle the
    /// next submit from this guest consumes, referenced or not. The
    /// caller's bytes are free to drop the moment this returns.
    public static ulong RegisterBlob(byte[] data) =>
        kaya_blob_register(data, (nuint)data.Length);

    /// Block for the next occurrence; false when the core has shut
    /// down. keys is empty when id is a widget id, else id is a
    /// template node id and keys is the stamped copy's key path,
    /// outermost first. payload carries the entry's new text (string)
    /// for OccKindTextChanged, the checkbox's new state (bool) for
    /// OccKindToggled, null for clicks.
    public static unsafe bool NextOccurrence(
        out ushort kind, out ulong id, out List<object> keys, out object payload)
    {
        uint* head = (uint*)ring.Head;
        uint* tail = (uint*)ring.Tail;
        byte* data = (byte*)ring.Data;
        uint mask = ring.Capacity - 1;

        uint h = Volatile.Read(ref *head);
        while (true)
        {
            uint t = Volatile.Read(ref *tail); // acquire: records below are visible
            if (h == t)
            {
                if (!kaya_wait_occurrences())
                {
                    kind = 0;
                    id = 0;
                    keys = new List<object>();
                    payload = null;
                    return false; // shutdown
                }
                continue;
            }
            byte* at = data + (h & mask);
            uint size = *(uint*)at;
            byte[] rec = new byte[size];
            Marshal.Copy((IntPtr)at, rec, 0, (int)size);
            bool valid = KayaWire.ParseOccurrence(rec, out kind, out id, out keys, out payload);
            h += size;
            Volatile.Write(ref *head, h); // release: hand the space back
            if (valid)
                return true;
        }
    }
}
